     */
    private boolean isOvernightSession() {
        return sessionClose.isBefore(sessionOpen);
    }

    /**
     * Factory method to create a new PricingSessionWindow assigner for a specific market.
     *
     * @param marketId The unique identifier for the market (e.g., "NYSE", "LSE", "CME").
     * @param timezone The timezone in which the session times are defined.
     * @param open The market opening time.
     * @param close The market closing time.
     * @return A new PricingSessionWindow instance configured for the specified market.
     */
    public static PricingSessionWindow forMarket(
            String marketId, ZoneId timezone, LocalTime open, LocalTime close) {
        return new PricingSessionWindow(marketId, timezone, open, close);
    }
}

