    LocalDate date = localDateTime.toLocalDate();

    // Determine which session this timestamp belongs to
    LocalDateTime sessionStartDateTime;
    LocalDateTime sessionEndDateTime;

    if (isOvernightSession()) {
        // Overnight sessions, e.g., 18:00 to 09:30 (close < open)
        if (timeOfDay.isBefore(sessionClose)) {
