            // This is the end of yesterday's overnight session
            sessionStartDateTime = LocalDateTime.of(date.minusDays(1), sessionOpen);
            sessionEndDateTime = LocalDateTime.of(date, sessionClose);
        } else {
            // Evening/late, at or after session open (e.g., 20:00, at or after 18:00)
            // This is the start of today's overnight session
            sessionStartDateTime = LocalDateTime.of(date, sessionOpen);
            sessionEndDateTime = LocalDateTime.of(date.plusDays(1), sessionClose);
        }
    } else {
        // Regular sessions, e.g., 09:30 to 16:00 (open < close)
        // All times within this date belong to today's session (including pre/post market)
        sessionStartDateTime = LocalDateTime.of(date, sessionOpen);
        sessionEndDateTime = LocalDateTime.of(date, sessionClose);
